package com.socialblog.notification.security;import org.springframework.beans.factory.annotation.Value;import org.springframework.context.annotation.*;import org.springframework.security.config.annotation.web.builders.HttpSecurity;import org.springframework.security.config.http.SessionCreationPolicy;import org.springframework.security.oauth2.jwt.*;import org.springframework.security.web.SecurityFilterChain;import javax.crypto.SecretKey;import javax.crypto.spec.SecretKeySpec;import java.nio.charset.StandardCharsets;@Configuration public class SecurityConfig{@Bean SecretKey key(@Value("${app.security.jwt-secret}")String s){return new SecretKeySpec(s.getBytes(StandardCharsets.UTF_8),"HmacSHA256");}@Bean JwtDecoder decoder(SecretKey k){return NimbusJwtDecoder.withSecretKey(k).build();}@Bean SecurityFilterChain chain(HttpSecurity h)throws Exception{return h.csrf(c->c.disable()).sessionManagement(s->s.sessionCreationPolicy(SessionCreationPolicy.STATELESS)).authorizeHttpRequests(a->a.requestMatchers("/actuator/health/**").permitAll().anyRequest().authenticated()).oauth2ResourceServer(o->o.jwt(j->{})).build();}}
